import{_ as e,o as a,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const m=JSON.parse('{"title":"macOS Permissions","description":"","frontmatter":{"summary":"macOS permission persistence (TCC) and signing requirements","read_when":["Debugging missing or stuck macOS permission prompts","Packaging or signing the macOS app","Changing bundle IDs or app install paths"],"title":"macOS Permissions"},"headers":[],"relativePath":"platforms/mac/permissions.md","filePath":"platforms/mac/permissions.md","lastUpdated":1771906665000}'),t={name:"platforms/mac/permissions.md"};function r(p,s,o,l,d,c){return a(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="macos-permissions-tcc" tabindex="-1"><a class="header-anchor" href="#macos-permissions-tcc">#</a> macOS permissions (TCC)</h1><p>macOS permission grants are fragile. TCC associates a permission grant with the app&#39;s code signature, bundle identifier, and on-disk path. If any of those change, macOS treats the app as new and may drop or hide prompts.</p><h2 id="requirements-for-stable-permissions" tabindex="-1"><a class="header-anchor" href="#requirements-for-stable-permissions">#</a> Requirements for stable permissions</h2><ul><li>Same path: run the app from a fixed location (for OpenSoul, <code>dist/OpenSoul.app</code>).</li><li>Same bundle identifier: changing the bundle ID creates a new permission identity.</li><li>Signed app: unsigned or ad-hoc signed builds do not persist permissions.</li><li>Consistent signature: use a real Apple Development or Developer ID certificate so the signature stays stable across rebuilds.</li></ul><p>Ad-hoc signatures generate a new identity every build. macOS will forget previous grants, and prompts can disappear entirely until the stale entries are cleared.</p><h2 id="recovery-checklist-when-prompts-disappear" tabindex="-1"><a class="header-anchor" href="#recovery-checklist-when-prompts-disappear">#</a> Recovery checklist when prompts disappear</h2><ol><li>Quit the app.</li><li>Remove the app entry in System Settings -&gt; Privacy &amp; Security.</li><li>Relaunch the app from the same path and re-grant permissions.</li><li>If the prompt still does not appear, reset TCC entries with <code>tccutil</code> and try again.</li><li>Some permissions only reappear after a full macOS restart.</li></ol><p>Example resets (replace bundle ID as needed):</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tccutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Accessibility</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ai.opensoul.mac</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tccutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ScreenCapture</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ai.opensoul.mac</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tccutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AppleEvents</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="files-and-folders-permissions-desktop-documents-downloads" tabindex="-1"><a class="header-anchor" href="#files-and-folders-permissions-desktop-documents-downloads">#</a> Files and folders permissions (Desktop/Documents/Downloads)</h2><p>macOS may also gate Desktop, Documents, and Downloads for terminal/background processes. If file reads or directory listings hang, grant access to the same process context that performs file operations (for example Terminal/iTerm, LaunchAgent-launched app, or SSH process).</p><p>Workaround: move files into the OpenSoul workspace (<code>~/.opensoul/workspace</code>) if you want to avoid per-folder grants.</p><p>If you are testing permissions, always sign with a real certificate. Ad-hoc builds are only acceptable for quick local runs where permissions do not matter.</p>`,13)])])}const u=e(t,[["render",r]]);export{m as __pageData,u as default};
